const crypto = require('crypto');
return items.map(({json}) => {
  const sourceUrl = json.link || json.url || json.sourceUrl;
  const canonicalUrl = String(sourceUrl || '').split('#')[0];
  const rawContent = json.content || json.contentSnippet || json.text || json.description || '';
  const externalId = String(json.guid || json.id || canonicalUrl);
  return {json:{externalId,sourcePlatform:json.sourcePlatform || 'rss',sourceName:json.feedTitle || json.sourceName || 'RSS',sourceUrl,canonicalUrl,author:json.creator || json.author || null,locale:json.locale || 'en',title:json.title,rawContent,imageUrl:json.imageUrl || null,publishedAt:json.isoDate || null,fingerprint:crypto.createHash('sha256').update(canonicalUrl+'|'+rawContent.replace(/\s+/g,' ').trim()).digest('hex'),category:json.category || 'ai'}};
});
